+    fn idempotency_key_expiry_semantics() {
+        let entry = IdempotencyEntry {
+            key: "test-key".to_string(),
+            zone_id: test_zone(),
+            intent_id: test_object_id("intent"),
+            receipt_id: Some(test_object_id("receipt")),
+            status: IntentStatus::Completed,
+            created_at: 1000,
